const generateArabicExams = () => {
    const config = [
        { unit: 1, count: 12, unitLabel: "الوحدة الأولى" },
        { unit: 2, count: 12, unitLabel: "الوحدة الثانية" },
        { unit: 3, count: 13, unitLabel: "الوحدة الثالثة" },
        { unit: 4, count: 13, unitLabel: "الوحدة الرابعة" },
        { unit: 5, count: 14, unitLabel: "الوحدة الخامسة" },
    ];

    const allExams: { title: string, url: string }[] = [];
    config.forEach(c => {
        for(let i = 1; i <= c.count; i++) {
            let branch = "Arabic-S1";
            if (c.unit === 1 && i === 1) {
                branch = "main";
            }
            allExams.push({
                title: `${c.unitLabel} - امتحان ${i}`,
                url: `https://raw.githubusercontent.com/MashalMath/joschool-11-arabic-exams/${branch}/arabic_s1_unit${c.unit}_exam${i}.json`
            });
        }
    });
    return allExams;
};

const ARABIC_EXAMS = generateArabicExams();
const ARABIC_UNIT_LABELS = ["الوحدة الأولى", "الوحدة الثانية", "الوحدة الثالثة", "الوحدة الرابعة", "الوحدة الخامسة"];
const ARABIC_UNIT_COUNTS = [12, 12, 13, 13, 14];

const App: React.FC = () => {
    const [viewHistory, setViewHistory] = useState<View[]>([View.Landing]);
    const [selectedSubject, setSelectedSubject] = useState<Subject | null>(null);
    const [currentQuiz, setCurrentQuiz] = useState<Question[]>([]);
    const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
    const [userAnswers, setUserAnswers] = useState<(string | null)[]>([]);
    const [showResults, setShowResults] = useState(false);
    const [expandedUnitIndices, setExpandedUnitIndices] = useState<number[]>([]);
    const [expandedLessonKeys, setExpandedLessonKeys] = useState<string[]>([]);
    const [isDbLoaded, setIsDbLoaded] = useState(false);
    const [showBackConfirmation, setShowBackConfirmation] = useState(false);
    const [showMultiBooksModal, setShowMultiBooksModal] = useState(false);

    const currentView = viewHistory[viewHistory.length - 1];

    const fetchExams = useCallback(() => {
        const examSets = [
            { subject: SubjectName.JordanHistory, exams: [...HISTORY_U1_EXAMS, ...HISTORY_U2_EXAMS, ...HISTORY_U3_EXAMS] },
            { subject: SubjectName.IslamicEducation, exams: [...ISLAMIC_U1_EXAMS, ...ISLAMIC_U2_EXAMS, ...ISLAMIC_U3_EXAMS, ...ISLAMIC_U4_EXAMS] },
            { subject: SubjectName.Arabic, exams: ARABIC_EXAMS }
        ];

        const allPromises: Promise<void>[] = [];

        examSets.forEach(set => {
            set.exams.forEach(item => {
                const p = fetch(item.url)
                    .then(res => {
                        if (!res.ok) return null;
                        return res.text();
                    })
                    .then(text => {
                        if (!text) return;
                        let cleanedText = text.replace(/^\uFEFF/, '').trim();
                        const firstBrace = cleanedText.indexOf('{');
                        const firstBracket = cleanedText.indexOf('[');
                        let start = -1;
                        let end = -1;

                        if (firstBrace !== -1 && (firstBracket === -1 || firstBrace < firstBracket)) {
                            start = firstBrace;
                            end = cleanedText.lastIndexOf('}');
                        } else if (firstBracket !== -1) {
                            start = firstBracket;
                            end = cleanedText.lastIndexOf(']');
                        }

                        if (start !== -1 && end !== -1 && end > start) {
                            cleanedText = cleanedText.substring(start, end + 1);
                        }
                        cleanedText = cleanedText.replace(/\u00A0/g, ' ');

                        try {
                            const data = JSON.parse(cleanedText);
                            const questions = Array.isArray(data) ? data : data.questions;
                            if (questions && questions.length > 0) {
                                updateDatabase(set.subject, item.title, questions);
                            }
                        } catch (parseError) {
                            if (!cleanedText.includes('404')) {
                                console.error(`Failed to parse JSON for ${item.url}:`, parseError);
                            }
                        }
                    })
                    .catch(e => {});
                allPromises.push(p);
            });
        });

        Promise.all(allPromises).finally(() => {
            setIsDbLoaded(true);
        });
    }, []);

    useEffect(() => {
        fetchExams();
        const handlePopState = () => {
            if (currentView === View.Quiz && !showResults) {
                window.history.pushState({ view: View.Quiz }, '');
                setShowBackConfirmation(true);
            } else {
                setViewHistory(prev => (prev.length > 1 ? prev.slice(0, -1) : prev));
            }
        };
        window.addEventListener('popstate', handlePopState);
        return () => window.removeEventListener('popstate', handlePopState);
    }, [fetchExams, currentView, showResults]);

    const navigateTo = (newView: View) => {
        window.history.pushState({ view: newView }, '');
        setViewHistory(prev => [...prev, newView]);
    };

    const goBack = () => {
        if (currentView === View.Quiz && !showResults) {
            setShowBackConfirmation(true);
        } else {
            window.history.back();
        }
    };

    const confirmLeaveQuiz = () => {
        setShowBackConfirmation(false);
        setViewHistory(prev => prev.slice(0, -1));
    };

    const goToHome = () => {
        setSelectedSubject(null);
        setShowResults(false);
        setViewHistory([View.Landing]);
    };

    const handleStartQuiz = (questions: Question[]) => {
        if (!questions || questions.length === 0) return;
        setCurrentQuiz([...questions]);
        setCurrentQuestionIndex(0);
        setUserAnswers(new Array(questions.length).fill(null));
        setShowResults(false);
        navigateTo(View.Quiz);
    };

    const handleStartComprehensiveExam = () => {
        if (!selectedSubject) return;
        const subjectData = examsDatabase[selectedSubject.id as SubjectName];
        if (!subjectData) {
            alert('عذراً، لا توجد امتحانات متوفرة لهذه المادة حالياً.');
            return;
        }

        const allQuestions: Question[] = [];
        Object.values(subjectData).forEach((lessonChunks) => {
            lessonChunks.forEach((chunk) => {
                allQuestions.push(...chunk);
            });
        });

        if (allQuestions.length === 0) {
            alert('عذراً، لا توجد أسئلة متوفرة حالياً.');
            return;
        }

        // اختيار 40 سؤال عشوائي أو كل الأسئلة إذا كانت أقل من 40
        const shuffled = allQuestions.sort(() => 0.5 - Math.random());
        handleStartQuiz(shuffled.slice(0, Math.min(40, shuffled.length)));
    };

    const toggleUnit = (idx: number) => {
        setExpandedUnitIndices(prev => prev.includes(idx) ? prev.filter(i => i !== idx) : [...prev, idx]);
    };

    const toggleLesson = (key: string) => {
        setExpandedLessonKeys(prev => prev.includes(key) ? prev.filter(k => k !== key) : [...prev, key]);
    };

    const openExternalBook = () => {
        if (selectedSubject?.multiBooks) {
            setShowMultiBooksModal(true);
        } else if (selectedSubject?.textbookUrl) {
            window.open(selectedSubject.textbookUrl, '_blank');
        } else {
            alert('عذراً، كتاب هذه المادة غير متوفر حالياً.');
        }
    };

    const LandingPage = () => (
        <div className="container mx-auto p-4 max-w-lg pt-6 text-right" dir="rtl">
            {[Semester.First, Semester.Second].map((sem) => (
                <div key={sem} className="mb-12">
                    <div className="flex items-center justify-between mb-6">
                        <div className="flex flex-col">
                            <div className="flex items-center gap-3 mb-1 pr-1">
                                <div className="w-1.5 h-10 bg-yellow-400 rounded-full"></div>
                                <h3 className="text-4xl font-black text-[#1e293b]">{sem}</h3>
                            </div>
                            <p className="text-slate-400 mr-5 font-bold text-sm">اختر مادة للبدء بمراجعة الدروس</p>
                        </div>
                    </div>

                    <div className="bg-[#1e40af] p-4 rounded-[2.25rem] shadow-xl grid grid-cols-2 gap-3 overflow-hidden">
                        {subjectsData.filter(s => s.semester === sem).map(s => {
                            const hasData = (s.id === SubjectName.JordanHistory || s.id === SubjectName.IslamicEducation || s.id === SubjectName.Arabic) && sem === Semester.First;
                            return (
                                <button 
                                    key={`${s.id}-${s.semester}`} 
                                    onClick={() => { setSelectedSubject(s); setExpandedUnitIndices([]); navigateTo(View.SubjectIndex); }} 
                                    className="bg-white p-2 rounded-2xl flex flex-row items-center gap-2 shadow-sm active:scale-95 min-h-[90px]"
                                >
                                    <img src={s.coverImage} className="w-11 h-16 object-cover rounded-lg shrink-0 shadow-sm" alt="" />
                                    <div className="flex-1 text-right overflow-hidden">
                                        <h4 className="text-[13px] font-black text-[#1e293b] whitespace-nowrap mb-1">{s.id}</h4>
                                        <span className={`text-[10px] font-bold ${hasData ? 'text-sky-500' : 'text-slate-300'}`}>
                                            {hasData ? 'متاح الآن' : 'قريباً'}
                                        </span>
                                    </div>
                                </button>
                            );
                        })}
                    </div>
                </div>
            ))}
        </div>
    );

    const SubjectIndexPage = () => {
        if (!selectedSubject) return null;
        const units = subjectIndexData[selectedSubject.id] || [];
        const isArabic = selectedSubject.id === SubjectName.Arabic;

        return (
            <div className="container mx-auto p-4 max-w-2xl pt-6 text-right" dir="rtl">
                {/* رأس الصفحة مع تبديل أماكن الغلاف والبطاقات */}
                <div className="flex flex-row items-start justify-between mb-10 gap-4">

                    {/* الجهة اليمنى (الآن): صورة الكتاب */}
                    <div className="relative shrink-0 w-28 h-40 group cursor-pointer order-1" onClick={openExternalBook}>
                        <img src={selectedSubject.coverImage} className="w-full h-full object-cover rounded-2xl shadow-xl border-2 border-white relative z-10" alt="" />
                        <div className="absolute -inset-2 bg-sky-100 rounded-[2.5rem] blur-xl opacity-40"></div>
                        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 z-20 w-14 h-14">
                            <div className="absolute inset-0 bg-green-500/20 rounded-full animate-pulse-inside"></div>
                            <button className="relative w-full h-full bg-green-600 rounded-full flex flex-col items-center justify-center text-white shadow-lg border-2 border-white/50 animate-soft-pulse">
                                <span className="text-[10px] font-black leading-none mb-0.5">افتح</span>
                                <span className="text-[10px] font-black leading-none">الكتاب</span>
                            </button>
                        </div>
                    </div>

                    {/* الوسط: عنوان المادة */}
                    <div className="flex flex-col flex-1 pr-4 pt-2 order-2">
                        <h2 className="text-3xl font-black text-slate-800 leading-tight mb-1">{selectedSubject.id}</h2>
                        <div className="flex items-center gap-2">
                            <span className="text-xs font-bold text-slate-400">تصفح الوحدات والدروس</span>
                        </div>
                    </div>

                    {/* الجهة اليسرى (الآن): البطاقات التفاعلية - تم زيادة الطول بشكل مستطيل أكثر */}
                    <div className="flex flex-col gap-3 w-1/4 order-3">
                        <button className="bg-white py-6 px-3 rounded-2xl shadow-md border border-slate-50 flex items-center justify-between active:scale-95 transition-transform min-h-[70px]">
                            <BookmarkOutlineIcon className="w-5 h-5 text-sky-500" />
                            <span className="text-[11px] font-black text-slate-700">المفضلة</span>
                        </button>
                        <button 
                            onClick={handleStartComprehensiveExam}
                            className="bg-[#0ea5e9] py-6 px-3 rounded-2xl shadow-lg flex items-center justify-between text-white active:scale-95 transition-transform min-h-[70px]"
                        >
                            <StarIcon className="w-5 h-5 text-white" />
                            <span className="text-[11px] font-black">امتحان شامل</span>
                        </button>
                    </div>
                </div>

                <div className="space-y-4">
                    {units.map((unit, uIdx) => (
                        <div key={uIdx} className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
                            <button onClick={() => toggleUnit(uIdx)} className="w-full p-5 flex items-center justify-between transition-colors hover:bg-slate-50 text-right">
                                <span className="font-black text-slate-800 text-base">{unit.title}</span>
                                <ChevronDownIcon className={`w-5 h-5 transition-transform ${expandedUnitIndices.includes(uIdx) ? 'rotate-180 text-sky-500' : 'text-slate-300'}`} />
                            </button>
                            {expandedUnitIndices.includes(uIdx) && (
                                <div className="px-5 pb-5">
                                    {isArabic ? (
                                        <div className="grid grid-cols-5 gap-3 animate-fast-fade">
                                            {Array.from({ length: ARABIC_UNIT_COUNTS[uIdx] }).map((_, i) => {
                                                const examTitle = `${ARABIC_UNIT_LABELS[uIdx]} - امتحان ${i + 1}`;
                                                const quizChunks = getQuizzesForLesson(SubjectName.Arabic, examTitle);
                                                const hasData = quizChunks && quizChunks.length > 0;
                                                return (
                                                    <button 
                                                        key={i} 
                                                        onClick={() => hasData && handleStartQuiz(quizChunks[0])} 
                                                        className={`w-full aspect-square bg-white border-2 rounded-xl font-black text-sm flex items-center justify-center shadow-sm transition-all ${hasData ? 'border-sky-500 text-sky-600 active:scale-90 hover:bg-sky-50' : 'border-slate-100 text-slate-300 grayscale opacity-50 cursor-not-allowed'}`}
                                                    >
                                                        {i + 1}
                                                    </button>
                                                );
                                            })}
                                        </div>
                                    ) : (
                                        <div className="space-y-2">
                                            {unit.lessons.map((lesson, lIdx) => {
                                                const quizzes = getQuizzesForLesson(selectedSubject.id as SubjectName, lesson.title);
                                                const lessonKey = `${uIdx}-${lIdx}`;
                                                const isExpanded = expandedLessonKeys.includes(lessonKey);
                                                return (
                                                    <div key={lIdx} className="overflow-hidden">
                                                        <button onClick={() => toggleLesson(lessonKey)} className={`w-full p-4 rounded-2xl flex items-center justify-between transition-all ${isExpanded ? 'bg-sky-50 text-sky-700' : 'bg-slate-50 text-slate-700'} border border-transparent hover:border-sky-100`}>
                                                            <span className="font-bold text-sm leading-relaxed text-right">{lesson.title}</span>
                                                            <ChevronDownIcon className={`w-4 h-4 transition-transform shrink-0 mr-2 ${isExpanded ? 'rotate-180 text-sky-500' : 'text-slate-300'}`} />
                                                        </button>
                                                        {isExpanded && (
                                                            <div className="p-4 grid grid-cols-5 gap-3 animate-fast-fade">
                                                                {quizzes && quizzes.length > 0 ? (
                                                                    quizzes.map((q, idx) => (
                                                                        <button key={idx} onClick={() => handleStartQuiz(q)} className="w-full aspect-square bg-white border-2 border-sky-500 text-sky-600 rounded-xl font-black text-sm flex items-center justify-center shadow-sm active:scale-90 transition-all hover:bg-sky-50">
                                                                            {idx + 1}
                                                                        </button>
                                                                    ))
                                                                ) : <span className="col-span-5 text-xs text-slate-400 font-bold py-2 text-center italic">قريباً إن شاء الله</span>}
                                                            </div>
                                                        )}
                                                    </div>
                                                );
                                            })}
                                        </div>
                                    )}
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            </div>
        );
    };

    const QuizPage = () => {
        const q = currentQuiz[currentQuestionIndex];
        if (!q) return null;
        const progress = ((currentQuestionIndex + 1) / currentQuiz.length) * 100;
        const arabicSymbols = ['أ', 'ب', 'ج', 'د'];
        return (
            <div className="container mx-auto p-4 max-xl pt-6 text-right" dir="rtl">
                <div className="bg-white rounded-[2.5rem] p-8 shadow-xl border border-slate-50">
                    <div className="flex items-center justify-between mb-8">
                        <div className="bg-sky-50 text-sky-600 px-4 py-1.5 rounded-full text-xs font-black">سؤال {currentQuestionIndex + 1} من {currentQuiz.length}</div>
                        <div className="flex-1 mx-4 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                            <div className="h-full bg-sky-400 transition-all duration-300" style={{ width: `${progress}%` }}></div>
                        </div>
                    </div>
                    <h3 className="text-xl font-black text-slate-800 mb-10 text-center leading-relaxed">{q.question}</h3>
                    <div className="space-y-3">
                        {q.choices.map((c, i) => (
                            <button key={i} onClick={() => setUserAnswers(prev => { const next = [...prev]; next[currentQuestionIndex] = c; return next; })} className={`w-full p-5 rounded-2xl border-2 text-right font-bold transition-all ${userAnswers[currentQuestionIndex] === c ? 'border-sky-500 bg-sky-50 text-sky-600' : 'border-slate-50 hover:border-slate-200 bg-slate-50/50'}`}>
                                <span className="inline-block w-6 h-6 rounded-full border border-slate-300 ml-3 text-center text-xs leading-6 font-naskh">{arabicSymbols[i] || i + 1}</span>
                                {c}
                            </button>
                        ))}
                    </div>
                    <div className="flex gap-3 mt-10">
                        {currentQuestionIndex < currentQuiz.length - 1 ? (
                            <button onClick={() => setCurrentQuestionIndex(prev => prev + 1)} disabled={!userAnswers[currentQuestionIndex]} className="w-full py-5 bg-sky-500 text-white rounded-2xl font-black shadow-lg disabled:opacity-50">السؤال التالي</button>
                        ) : (
                            <button onClick={() => setShowResults(true)} disabled={!userAnswers[currentQuestionIndex]} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black shadow-lg disabled:opacity-50">عرض النتيجة</button>
                        )}
                    </div>
                </div>
            </div>
        );
    };

    const ResultsPage = () => {
        const score = userAnswers.reduce((acc, ans, idx) => acc + (ans?.trim() === currentQuiz[idx].correct_answer?.trim() ? 1 : 0), 0);
        const markFrom40 = Math.round((score / currentQuiz.length) * 40);
        const isPassed = markFrom40 >= 20;
        return (
            <div className="container mx-auto p-4 max-w-xl text-center pt-10" dir="rtl">
                <div className="bg-white rounded-[3rem] p-8 shadow-2xl border border-slate-50 mb-8 text-center">
