                    </div>
                    <button onClick={() => setViewHistory(prev => prev.slice(0, -1))} className={`w-full py-5 text-white rounded-2xl font-black shadow-xl mb-4 ${isPassed ? 'bg-green-600' : 'bg-slate-900'}`}>{isPassed ? 'العودة للقائمة' : 'إعادة المحاولة'}</button>
                </div>
            </div>
        );
    };

    const currentViewComponent = () => {
        if (!isDbLoaded) return (
            <div className="flex flex-col items-center justify-center h-[80vh]">
                <div className="w-16 h-16 border-4 border-sky-500 border-t-transparent rounded-full animate-spin mb-6"></div>
                <p className="font-black text-slate-600 text-lg">جاري تجهيز الاختبارات الذكية...</p>
            </div>
        );
        switch (currentView) {
            case View.Landing: return <LandingPage />;
            case View.SubjectIndex: return <SubjectIndexPage />;
            case View.Quiz: return showResults ? <ResultsPage /> : <QuizPage />;
            case View.SessionSubjects: return <div className="p-10 text-center font-black">قريباً إن شاء الله</div>;
            default: return <LandingPage />;
        }
    };

    return (
        <div className="min-h-screen bg-[#f8fafc]">
            <header className="w-full bg-white shadow-sm sticky top-0 z-40 h-20 flex items-center px-6">
                <div className="flex-1">{viewHistory.length > 1 && <button onClick={goBack} className="p-3 bg-slate-50 rounded-xl"><ArrowLeftIcon className="w-6 h-6 transform scale-x-[-1]" /></button>}</div>
                <div className="text-center cursor-pointer" onClick={goToHome}><h1 className="text-xl font-black text-slate-900 leading-none">JoSchool <span className="text-sky-500">11</span></h1><span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest font-sans">Generation 2009</span></div>
                <div className="flex-1"></div>
            </header>
            <main className="transition-smooth pb-10">{currentViewComponent()}</main>
            {showBackConfirmation && <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm animate-fast-fade" dir="rtl"><div className="bg-white w-full max-w-xs rounded-[2.5rem] p-8 shadow-2xl"><h3 className="text-xl font-black text-slate-800 text-center mb-8">هل تريد مغادرة الاختبار؟</h3><div className="space-y-3"><button onClick={() => setShowBackConfirmation(false)} className="w-full py-4 bg-sky-500 text-white rounded-2xl font-black shadow-lg">إكمال الاختبار</button><button onClick={confirmLeaveQuiz} className="w-full py-4 bg-slate-100 text-slate-600 rounded-2xl font-black">العودة للفهرس</button></div></div></div>}
            {showMultiBooksModal && <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm" dir="rtl"><div className="bg-white w-full max-w-xs rounded-[3rem] p-8 shadow-2xl relative"><button onClick={() => setShowMultiBooksModal(false)} className="absolute top-6 left-6 p-2 bg-slate-50 rounded-full"><XIcon className="w-5 h-5"/></button><h3 className="text-2xl font-black text-slate-800 text-center mb-8 pt-2">اختر الكتاب</h3><div className="space-y-4">{selectedSubject?.multiBooks?.map((book, idx) => (<button key={idx} onClick={() => { window.open(book.url, '_blank'); setShowMultiBooksModal(false); }} className="w-full p-6 bg-slate-50 border-2 border-slate-100 rounded-[2rem] flex items-center gap-3 transition-all hover:bg-sky-50 group"><div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center"><BookOpenIcon className="w-5 h-5 text-sky-500" /></div><span className="text-lg font-black text-slate-700">{book.label}</span></button>))}</div></div></div>}
        </div>
    );
};

export default App;

